import jwt
from jwt.exceptions import InvalidTokenError, ExpiredSignatureError, MissingRequiredClaimError
import json

def decode_and_verify_jwt(token, secret, algorithms=['HS256']):
    """
    Securely decode and verify JWT token for debugging purposes.
    
    Args:
        token (str): The JWT token to decode and verify
        secret (str): The secret key for verification
        algorithms (list): List of allowed algorithms (required for security)
    
    Returns:
        dict: Decoded token payload if valid, None if invalid
    
    Raises:
        ValueError: If token is invalid or verification fails
    """
    try:
        # Verify algorithm is explicitly allowed
        if not algorithms:
            raise ValueError("Algorithms list cannot be empty")
        
        # Decode and verify the token with strict validation
        payload = jwt.decode(
            token,
            secret,
            algorithms=algorithms,
            options={
                "require": ["exp", "iat"],  # Require essential claims
                "verify_signature": True,
                "verify_exp": True,
                "verify_iat": True
            }
        )
        
        return payload
        
    except ExpiredSignatureError:
        raise ValueError("Token has expired")
    except MissingRequiredClaimError as e:
        raise ValueError(f"Missing required claim: {str(e)}")
    except InvalidTokenError as e:
        raise ValueError(f"Invalid token: {str(e)}")
    except Exception as e:
        raise ValueError(f"Token verification failed: {str(e)}")

